# Load package info
with open(locals()['var_function-call-7276057552529987536'], 'r') as f:
    pkg_data = json.load(f)

# Also include the tailwindcss from before if not in this list
# But wait, tailwindcss was in the list requested. (Yes, @dumc11/tailwindcss)
# So it should be in pkg_data unless file truncated. 
# The preview showed lots of rows.

valid_packages = {} # Name -> {Version, PubAt}

for row in pkg_data:
    name = row['Name']
    try:
        ver_info = json.loads(row['VersionInfo'])
    except:
        continue

    if not ver_info.get('IsRelease', False):
        continue

    pub_at = float(row['UpstreamPublishedAt']) if row['UpstreamPublishedAt'] else 0.0
    version = row['Version']

    if name not in valid_packages:
        valid_packages[name] = {'Version': version, 'PubAt': pub_at}
    else:
        if pub_at > valid_packages[name]['PubAt']:
            valid_packages[name] = {'Version': version, 'PubAt': pub_at}

# Load candidates with stars
candidates = locals()['var_function-call-2044505968345615433']
# Map Name -> Stars
star_map = {c['Name']: c['Stars'] for c in candidates}

final_list = []
for name, info in valid_packages.items():
    if name in star_map:
        final_list.append({
            'Name': name,
            'Version': info['Version'],
            'Stars': star_map[name]
        })

# Sort by Stars desc
final_list.sort(key=lambda x: x['Stars'], reverse=True)

print("__RESULT__:")
print(json.dumps(final_list[:5]))"}

